/**
 * Order validation — pure functions for validating order input and state transitions.
 *
 * Extracted from OrderService to enable reuse and independent testing.
 * No side effects, no database calls.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';

/**
 * Allowed status transitions for orders.
 * Each key maps to the set of statuses it can transition to.
 */
export const ORDER_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return ORDER_STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate input for creating an order.
 * Throws if the input is invalid.
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Notification validation — pure functions for validating notification-related data.
 *
 * Extracted from EmailAdapter to enable reuse across adapters and services.
 * No side effects, no database calls.
 */

/**
 * Check whether a string is a valid email address format.
 */
export function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * Normalize an email address: trim whitespace and convert to lowercase.
 */
export function normalizeEmail(email: string): string {
  return email.trim().toLowerCase();
}

/**
 * Validate and normalize a recipient email address.
 * Returns the normalized email or throws if the format is invalid.
 */
export function validateRecipientEmail(recipient: string): string {
  const normalized = normalizeEmail(recipient);
  if (!isValidEmail(normalized)) {
    throw new Error(`Invalid email address: ${recipient}`);
  }
  return normalized;
}

