import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateCreateOrderInput,
  ORDER_STATUS_TRANSITIONS,
} from '../../src/validators/order.validator.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('validateCreateOrderInput', () => {
    it('should accept input with items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should reject empty items', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });
  });

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('delivered', status)).toBe(false);
      }
    });

    it('should reject cancelled -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(isValidStatusTransition('cancelled', status)).toBe(false);
      }
    });
  });

  describe('ORDER_STATUS_TRANSITIONS', () => {
    it('should define transitions for all statuses', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const status of statuses) {
        expect(ORDER_STATUS_TRANSITIONS).toHaveProperty(status);
        expect(Array.isArray(ORDER_STATUS_TRANSITIONS[status])).toBe(true);
      }
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  isValidEmail,
  normalizeEmail,
  validateRecipientEmail,
} from '../../src/validators/notification.validator.js';

describe('notification.validator', () => {
  describe('isValidEmail', () => {
    it('should accept valid emails', () => {
      expect(isValidEmail('alice@example.com')).toBe(true);
      expect(isValidEmail('bob.smith@company.co')).toBe(true);
      expect(isValidEmail('user+tag@domain.org')).toBe(true);
    });

    it('should reject emails without @', () => {
      expect(isValidEmail('alice-example.com')).toBe(false);
    });

    it('should reject emails without domain', () => {
      expect(isValidEmail('alice@')).toBe(false);
    });

    it('should reject emails without local part', () => {
      expect(isValidEmail('@example.com')).toBe(false);
    });

    it('should reject emails with spaces', () => {
      expect(isValidEmail('alice @example.com')).toBe(false);
    });

    it('should reject empty string', () => {
      expect(isValidEmail('')).toBe(false);
    });
  });

  describe('normalizeEmail', () => {
    it('should trim whitespace', () => {
      expect(normalizeEmail('  alice@example.com  ')).toBe('alice@example.com');
    });

    it('should convert to lowercase', () => {
      expect(normalizeEmail('Alice@Example.COM')).toBe('alice@example.com');
    });

    it('should handle already normalized emails', () => {
      expect(normalizeEmail('alice@example.com')).toBe('alice@example.com');
    });
  });

  describe('validateRecipientEmail', () => {
    it('should return normalized email for valid input', () => {
      expect(validateRecipientEmail('  Alice@Example.COM  ')).toBe('alice@example.com');
    });

    it('should return normalized email for simple valid input', () => {
      expect(validateRecipientEmail('bob@test.org')).toBe('bob@test.org');
    });

    it('should throw for invalid email', () => {
      expect(() => validateRecipientEmail('not-an-email')).toThrow(
        'Invalid email address: not-an-email',
      );
    });

    it('should throw for empty string', () => {
      expect(() => validateRecipientEmail('')).toThrow('Invalid email address:');
    });
  });
});

